import type { ChangeEvent, MouseEvent } from 'react';
import React from 'react';
import type { CheckBoxChangeEvent, CheckboxProps } from '../../../checkbox';
import { Checkbox } from '../../../checkbox';
import type { RadioChangeEvent } from '../../../radio';
import { Radio } from '../../../radio';
import { SELECTION_TYPE_RADIO } from '../../constants';
import type { RowSelectionType } from '../../interface';

interface SelectionConfig extends Partial<CheckboxProps> {
  type: RowSelectionType;
  checked: boolean;
  onSelect: (event: ChangeEvent<HTMLInputElement>) => void;
}

function SelectionCell(props: SelectionConfig) {
  const { type, onSelect, checked, ...rest } = props;

  const onClick = (event: MouseEvent) => event.stopPropagation();

  const handleRadioOnChange = (e: RadioChangeEvent) => {
    onSelect(e.reactEvent);
  };

  const handleCheckBoxOnChange = (e: CheckBoxChangeEvent) => {
    onSelect(e.reactEvent);
  };

  if (type === SELECTION_TYPE_RADIO) {
    return <Radio checked={checked} onClick={onClick} onChange={handleRadioOnChange} />;
  }
  return <Checkbox {...rest} checked={checked} onClick={onClick} onChange={handleCheckBoxOnChange} />;
}

export default SelectionCell;
